+        assert_eq!(people[0].get_as::<i64>(0).unwrap(), id);
+        assert_eq!(people[0].get_named::<String>("name").unwrap(), "Alice");
+
+        let student_rows = unwrap_outcome(
+            conn.query(
+                &cx,
+                &format!("SELECT id, grade FROM {student_table} WHERE id = ?1"),
+                &[Value::BigInt(id)],
+            )
+            .await,
+        );
